#!/usr/bin/env node
// Patches the `android/app/build.gradle` generated by `expo prebuild` to sign release builds
// with a dedicated keystore instead of Expo's default debug keystore.
//
// Why: `expo prebuild` regenerates `android/` from scratch every run, so any signing config has
// to be re-applied here rather than committed directly into build.gradle.
//
// Reads from the environment (no secrets ever touch disk as plain args):
//   MEMBERR_KEYSTORE_PATH      - absolute path to the .keystore file
//   MEMBERR_KEYSTORE_PASSWORD
//   MEMBERR_KEY_ALIAS
//   MEMBERR_KEY_PASSWORD
//
// If MEMBERR_KEYSTORE_PATH isn't set, the release build type keeps using the debug keystore
// (unchanged from Expo's default), so local `expo run:android` is unaffected.
//
// Run this after `expo prebuild --platform android` and before `./gradlew assembleRelease`.

import { readFileSync, writeFileSync } from 'node:fs'
import { fileURLToPath } from 'node:url'
import path from 'node:path'

const gradlePath = path.resolve(
  path.dirname(fileURLToPath(import.meta.url)),
  '../android/app/build.gradle'
)

let gradle = readFileSync(gradlePath, 'utf8')

// Anchor 1: Expo's default debug signingConfigs block — insert a `release` config next to it.
const debugSigningConfigBlock = `    signingConfigs {
        debug {
            storeFile file('debug.keystore')
            storePassword 'android'
            keyAlias 'androiddebugkey'
            keyPassword 'android'
        }
    }`

// Anchor 2: the comment Expo's template emits inside the `release` buildType — unique to that
// block, so this can't accidentally also patch the `debug` buildType's identical
// `signingConfig signingConfigs.debug` line.
const releaseBuildTypeAnchor = `            // Caution! In production, you need to generate your own keystore file.
            // see https://reactnative.dev/docs/signed-apk-android.
            signingConfig signingConfigs.debug`

if (!gradle.includes(debugSigningConfigBlock) || !gradle.includes(releaseBuildTypeAnchor)) {
  console.error(
    'apply-release-signing: expected anchor text not found in android/app/build.gradle.\n' +
      'The Expo prebuild template likely changed — update the anchors in this script before continuing,\n' +
      'otherwise the release APK could end up signed with the debug keystore unintentionally.'
  )
  process.exit(1)
}

const releaseSigningConfig = `    signingConfigs {
        debug {
            storeFile file('debug.keystore')
            storePassword 'android'
            keyAlias 'androiddebugkey'
            keyPassword 'android'
        }
        release {
            if (System.getenv("MEMBERR_KEYSTORE_PATH")) {
                storeFile file(System.getenv("MEMBERR_KEYSTORE_PATH"))
                storePassword System.getenv("MEMBERR_KEYSTORE_PASSWORD")
                keyAlias System.getenv("MEMBERR_KEY_ALIAS")
                keyPassword System.getenv("MEMBERR_KEY_PASSWORD")
            }
        }
    }`

const releaseBuildTypeSigning = `            // Caution! In production, you need to generate your own keystore file.
            // see https://reactnative.dev/docs/signed-apk-android.
            signingConfig System.getenv("MEMBERR_KEYSTORE_PATH") ? signingConfigs.release : signingConfigs.debug`

gradle = gradle
  .replace(debugSigningConfigBlock, releaseSigningConfig)
  .replace(releaseBuildTypeAnchor, releaseBuildTypeSigning)

writeFileSync(gradlePath, gradle)

console.log(
  process.env.MEMBERR_KEYSTORE_PATH
    ? 'apply-release-signing: release builds will be signed with MEMBERR_KEYSTORE_PATH.'
    : 'apply-release-signing: MEMBERR_KEYSTORE_PATH not set — release builds will fall back to the debug keystore.'
)
